import asyncio
import websockets
from collections import defaultdict

# In-memory database simulation
inventory = defaultdict(dict)

async def handle_connection(websocket, path):
    try:
        async for message in websocket:
            data = message.split(',')
            if len(data) != 3:
                await websocket.send("Invalid request")
                continue
            
            action, item_id, player_id = data[0], data[1], data[2]
            
            if action == "add":
                if player_id not in inventory:
                    inventory[player_id] = {}
                inventory[player_id][item_id] = True
                await websocket.send(f"Item {item_id} added to your inventory")
            elif action == "remove":
                if player_id in inventory and item_id in inventory[player_id]:
                    del inventory[player_id][item_id]
                    await websocket.send(f"Item {item_id} removed from your inventory")
                else:
                    await websocket.send("Item not found in your inventory")
            elif action == "trade":
                sender, receiver, item_id = player_id, data[3], item_id
                if sender in inventory and item_id in inventory[sender]:
                    del inventory[sender][item_id]
                    if receiver not in inventory:
                        inventory[receiver] = {}
                    inventory[receiver][item_id] = True
                    await websocket.send(f"Item {item_id} traded to {receiver}")
                else:
                    await websocket.send("Trade failed")
            else:
                await websocket.send("Invalid action")
    except websockets.exceptions.ConnectionClosed:
        pass

start_server = websockets.serve(handle_connection, "localhost", 8765)

asyncio.get_event_loop().run_until_complete(start_server)
asyncio.get_event_loop().run_forever()